#!/bin/bash
# scripts/setup-broker-webhook.sh
# One-time setup: configure Pact Broker webhook to trigger provider CI

PACT_BROKER_URL="${PACT_BROKER_URL}"
PACT_BROKER_TOKEN="${PACT_BROKER_TOKEN}"
GITHUB_TOKEN="${GITHUB_PAT}"
PROVIDER_REPO="myorg/search-tool-service"

curl -X POST "${PACT_BROKER_URL}/webhooks" \
  -H "Authorization: Bearer ${PACT_BROKER_TOKEN}" \
  -H "Content-Type: application/json" \
  -d '{
    "description": "Trigger provider verification on pact change",
    "events": [
      {"name": "contract_content_changed"},
      {"name": "contract_published"}
    ],
    "request": {
      "method": "POST",
      "url": "https://api.github.com/repos/'"${PROVIDER_REPO}"'/actions/workflows/provider-verification.yml/dispatches",
      "headers": {
        "Authorization": "Bearer '"${GITHUB_TOKEN}"'",
        "Content-Type": "application/json"
      },
      "body": {
        "ref": "main",
        "inputs": {
          "pact_url": "${pactbroker.pactUrl}"
        }
      }
    }
  }'
echo "Webhook configured."
